import * as React from "react"

import {
  CHART_HEIGHT_TOKENS,
  type ChartFrameSize,
} from "../lib/df-chart"
import { cn } from "../lib/utils"

export type { ChartFrameSize }

export type ChartFrameProps = Omit<
  React.HTMLAttributes<HTMLDivElement>,
  "title"
> & {
  title?: React.ReactNode
  description?: React.ReactNode
  toolbar?: React.ReactNode
  size?: ChartFrameSize
  loading?: boolean
  empty?: boolean
  emptyContent?: React.ReactNode
  children?: React.ReactNode
}

function ChartFrame({
  className,
  title,
  description,
  toolbar,
  size = "md",
  loading = false,
  empty = false,
  emptyContent,
  children,
  style,
  ...props
}: ChartFrameProps) {
  const heightToken = CHART_HEIGHT_TOKENS[size]
  const showHeader =
    title != null || description != null || toolbar != null

  return (
    <div
      data-df="chart-frame"
      data-size={size}
      className={cn(className)}
      style={style}
      {...props}
    >
      {showHeader ? (
        <div data-df="chart-frame-header">
          <div data-df="chart-frame-copy">
            {title != null ? (
              <div data-df="chart-frame-title">{title}</div>
            ) : null}
            {description != null ? (
              <div data-df="chart-frame-description">{description}</div>
            ) : null}
          </div>
          {toolbar != null ? (
            <div data-df="chart-frame-toolbar">{toolbar}</div>
          ) : null}
        </div>
      ) : null}

      {loading ? (
        <div
          data-df="chart-frame-loading"
          role="status"
          aria-busy="true"
          style={{ height: `var(${heightToken})` }}
        >
          <span className="df-chart-skeleton" />
        </div>
      ) : empty ? (
        <div
          data-df="chart-frame-empty"
          role="status"
          style={{ minHeight: `var(${heightToken})` }}
        >
          {emptyContent ?? "No data"}
        </div>
      ) : (
        <div
          data-df="chart-frame-plot"
          style={{ height: `var(${heightToken})`, width: "100%" }}
        >
          {children}
        </div>
      )}
    </div>
  )
}

export type ChartTooltipPayloadItem = {
  name?: string
  value?: number | string | Array<number | string>
  color?: string
  dataKey?: string | number
  payload?: unknown
}

export type ChartTooltipProps = {
  active?: boolean
  label?: React.ReactNode
  payload?: readonly ChartTooltipPayloadItem[]
  className?: string
  formatValue?: (
    value: ChartTooltipPayloadItem["value"],
    item: ChartTooltipPayloadItem
  ) => React.ReactNode
}

function defaultTooltipValue(
  value: ChartTooltipPayloadItem["value"]
): React.ReactNode {
  if (value == null) return ""
  if (Array.isArray(value)) return value.join(" to ")
  return value
}

function ChartTooltip({
  active,
  label,
  payload,
  className,
  formatValue,
}: ChartTooltipProps) {
  if (!active || payload == null || payload.length === 0) return null

  return (
    <div data-df="chart-tooltip" className={cn(className)}>
      {label != null && label !== "" ? (
        <div data-df="chart-tooltip-label">{label}</div>
      ) : null}
      <ul data-df="chart-tooltip-rows">
        {payload.map((item, index) => {
          const key = String(item.dataKey ?? item.name ?? index)
          const displayValue =
            formatValue != null
              ? formatValue(item.value, item)
              : defaultTooltipValue(item.value)
          return (
            <li key={key} data-df="chart-tooltip-row">
              <span
                data-df="chart-tooltip-swatch"
                aria-hidden
                style={
                  item.color != null
                    ? { backgroundColor: item.color }
                    : undefined
                }
              />
              <span data-df="chart-tooltip-name">{item.name ?? key}</span>
              <span data-df="chart-tooltip-value">{displayValue}</span>
            </li>
          )
        })}
      </ul>
    </div>
  )
}

export type ChartLegendItem = {
  id: string
  label: React.ReactNode
  color: string
}

export type ChartLegendProps = Omit<
  React.HTMLAttributes<HTMLUListElement>,
  "children"
> & {
  items: readonly ChartLegendItem[]
}

function ChartLegend({ items, className, ...props }: ChartLegendProps) {
  if (items.length === 0) return null

  return (
    <ul data-df="chart-legend" className={cn(className)} {...props}>
      {items.map((item) => (
        <li key={item.id} data-df="chart-legend-item">
          <span
            data-df="chart-legend-swatch"
            aria-hidden
            style={{ backgroundColor: item.color }}
          />
          <span data-df="chart-legend-label">{item.label}</span>
        </li>
      ))}
    </ul>
  )
}

export { ChartFrame, ChartLegend, ChartTooltip }

/**
 * Ordered categorical series tokens. Values are CSS custom property names
 * without the surrounding var().
 */
export const CHART_SERIES_TOKENS = [
  "--df-chart-series-1",
  "--df-chart-series-2",
  "--df-chart-series-3",
  "--df-chart-series-4",
  "--df-chart-series-5",
  "--df-chart-series-6",
  "--df-chart-series-7",
  "--df-chart-series-8",
  "--df-chart-series-9",
  "--df-chart-series-10",
  "--df-chart-series-11",
  "--df-chart-series-12",
] as const

export type ChartSeriesToken = (typeof CHART_SERIES_TOKENS)[number]

export type ChartFrameSize = "sm" | "md" | "lg"

/** CSS height custom property for a named chart frame size. */
export const CHART_HEIGHT_TOKENS = {
  sm: "--df-chart-height-sm",
  md: "--df-chart-height-md",
  lg: "--df-chart-height-lg",
} as const satisfies Record<ChartFrameSize, string>

/** Cycle the categorical series palette and return a CSS `var(--…)` string. */
export function chartSeriesColor(index: number): string {
  const length = CHART_SERIES_TOKENS.length
  const normalized = ((Math.trunc(index) % length) + length) % length
  return `var(${CHART_SERIES_TOKENS[normalized]!})`
}

/** Theme values shaped for common Cartesian chart prop bags. */
export const chartTheme = {
  grid: {
    stroke: "var(--df-chart-grid)",
    strokeOpacity: 0.7,
  },
  axis: {
    tickLine: false as const,
    axisLine: false as const,
    tick: {
      fill: "var(--df-chart-axis-fg)",
      fontSize: "var(--df-chart-axis-font-size)",
    },
  },
  tooltip: {
    background: "var(--df-chart-tooltip-bg)",
    border: "var(--border-width-hairline) solid var(--df-chart-tooltip-border)",
    borderRadius: "var(--df-chart-tooltip-radius)",
    boxShadow: "var(--df-chart-tooltip-shadow)",
    color: "var(--df-chart-tooltip-fg)",
    fontSize: "var(--df-chart-tooltip-font-size)",
    padding: "var(--df-chart-tooltip-padding)",
  },
  reference: {
    stroke: "var(--df-chart-reference)",
  },
  trend: {
    positive: "var(--df-chart-trend-positive)",
    negative: "var(--df-chart-trend-negative)",
    neutral: "var(--df-chart-trend-neutral)",
  },
} as const

export type ChartTheme = typeof chartTheme

import { toDate } from "../df-date/index"

export type ChartDateGranularity = "day" | "week" | "month" | "quarter" | "year"

function trimCompact(value: number): string {
  const fixed = value.toFixed(1)
  return fixed.endsWith(".0") ? fixed.slice(0, -2) : fixed
}

/** Compact axis and tooltip numbers: 1.2k, 3.4M, 1.1B. */
export function formatChartNumber(value: number): string {
  if (!Number.isFinite(value)) return ""
  if (value === 0) return "0"

  const sign = value < 0 ? "-" : ""
  const abs = Math.abs(value)

  if (abs >= 1_000_000_000) {
    return `${sign}${trimCompact(abs / 1_000_000_000)}B`
  }
  if (abs >= 1_000_000) {
    return `${sign}${trimCompact(abs / 1_000_000)}M`
  }
  if (abs >= 1_000) {
    return `${sign}${trimCompact(abs / 1_000)}k`
  }
  if (Number.isInteger(abs)) {
    return `${sign}${abs}`
  }
  return `${sign}${trimCompact(abs)}`
}

function monthShort(date: Date): string {
  return date.toLocaleString("en-US", { month: "short", timeZone: "UTC" })
}

/**
 * Short day or month labels for an ISO timestamp at a given granularity.
 * Uses UTC calendar fields.
 */
export function formatChartDate(
  iso: string,
  granularity: ChartDateGranularity
): string {
  const date = toDate(iso)
  const day = date.getUTCDate()
  const year = date.getUTCFullYear()
  const month = monthShort(date)

  switch (granularity) {
    case "day":
    case "week":
      return `${month} ${day}`
    case "month":
      return month
    case "quarter": {
      const quarter = Math.floor(date.getUTCMonth() / 3) + 1
      return `Q${quarter}`
    }
    case "year":
      return String(year)
    default: {
      const _exhaustive: never = granularity
      return _exhaustive
    }
  }
}

export type ChartPoint = {
  x: number
  y: number
  label?: string
}

export type ChartSeries = {
  id: string
  points: ChartPoint[]
}

export type ChartBounds = {
  minX: number
  maxX: number
  minY: number
  maxY: number
}

export type SvgPoint = {
  x: number
  y: number
}

/** Inclusive bounds for one or more series. Empty input returns zeros. */
export function seriesBounds(series: readonly ChartSeries[]): ChartBounds {
  let minX = Number.POSITIVE_INFINITY
  let maxX = Number.NEGATIVE_INFINITY
  let minY = Number.POSITIVE_INFINITY
  let maxY = Number.NEGATIVE_INFINITY
  let count = 0
  for (const row of series) {
    for (const point of row.points) {
      count += 1
      minX = Math.min(minX, point.x)
      maxX = Math.max(maxX, point.x)
      minY = Math.min(minY, point.y)
      maxY = Math.max(maxY, point.y)
    }
  }
  if (count === 0) {
    return { minX: 0, maxX: 1, minY: 0, maxY: 1 }
  }
  if (minX === maxX) maxX = minX + 1
  if (minY === maxY) maxY = minY + 1
  return { minX, maxX, minY, maxY }
}

/** Map data points into an SVG plot box. */
export function projectSeriesToSvg(
  series: ChartSeries,
  bounds: ChartBounds,
  width: number,
  height: number,
  padding = 8
): SvgPoint[] {
  const innerW = Math.max(width - padding * 2, 1)
  const innerH = Math.max(height - padding * 2, 1)
  const spanX = bounds.maxX - bounds.minX
  const spanY = bounds.maxY - bounds.minY
  return series.points.map((point) => ({
    x: padding + ((point.x - bounds.minX) / spanX) * innerW,
    y: padding + (1 - (point.y - bounds.minY) / spanY) * innerH,
  }))
}

export function polylinePath(points: readonly SvgPoint[]): string {
  if (points.length === 0) return ""
  return points
    .map((point, index) => `${index === 0 ? "M" : "L"}${point.x},${point.y}`)
    .join(" ")
}

/** Cumulative burndown-style remaining series from daily burn values. */
export function remainingFromBurns(
  startRemaining: number,
  burns: readonly number[]
): ChartPoint[] {
  let remaining = startRemaining
  const points: ChartPoint[] = [{ x: 0, y: remaining }]
  burns.forEach((burn, index) => {
    remaining = Math.max(0, remaining - burn)
    points.push({ x: index + 1, y: remaining })
  })
  return points
}
